 18→constexpr int FRACBITS = 16;
 19→
 20→typedef int32_t fix;				//16 bits int, 16 bits frac
 21→typedef short fixang;		//angles
 22→
 23→//Some handy constants
 24→#define f0_0	0
 25→#define f1_0	0x10000
 26→#define f2_0	0x20000
 27→#define f3_0	0x30000
 28→#define f10_0	0xa0000
 29→
 30→#define f0_5 0x8000
 31→#define f0_1 0x199a
 32→
 33→#define F0_0	f0_0
 34→#define F1_0	f1_0
 35→#define F2_0	f2_0
 36→#define F3_0	f3_0
 37→#define F10_0	f10_0
 38→
 39→#define F0_5 	f0_5
 40→#define F0_1 	f0_1
 41→
 42→typedef struct quad 
 43→{
 44→	uint32_t low;
 45→	int32_t high;
 46→} quad;
 47→
 48→//Convert an int to a fix
 49→constexpr fix i2f(int i)
 50→{
 51→	return i << FRACBITS;
 52→}
 53→
 54→//Get the int part of a fix
 55→constexpr int f2i(fix f)
 56→{
 57→	return f >> FRACBITS;
 58→}
 59→
 60→constexpr int f2iu(unsigned int f)
 61→{
 62→	return f >> FRACBITS;
 63→}
 64→
 65→//Get the int part of a fix, with rounding
 66→constexpr int f2ir(int f)
 67→{
 68→	return (f + F0_5) >> FRACBITS;
 69→}
 70→
 71→//Convert fix to float and float to fix
 72→constexpr float f2fl(fix f)
 73→{
 74→	return f / 65536.0f;
 75→}
 76→
 77→constexpr fix fl2f(float f)
 78→{
 79→	return (fix)(f * 65536);
 80→}
 81→
 82→//multiply two fixes, return a fix
 83→constexpr fix fixmul(fix a, fix b)
 84→{
 85→	return ((int64_t)a * (int64_t)b) >> FRACBITS;
 86→}
 87→
 88→//divide two fixes, return a fix
 89→constexpr fix fixdiv(fix a, fix b)
 90→{
 91→	//[ISB] TODO: Why did I put this here? if it's div0ing something's wrong. The original game doesn't allow it. 
 92→	if (b == 0) return 1;
 93→
 94→	return (fix)(((int64_t)a << 16) / b);
 95→}
 96→
 97→//multiply two fixes, then divide by a third, return a fix
 98→constexpr fix fixmuldiv(fix a, fix b, fix c)
 99→{
100→	if (c == 0) return 1;
101→
102→	return (fix)((int64_t)a * (int64_t)b / c);
103→}
104→
105→//multiply two fixes, and add 64-bit product to a quad
106→void fixmulaccum(int64_t*q, fix a, fix b);
107→
108→//extract a fix from a quad product
109→fix fixquadadjust(int64_t q);
110→
111→//divide a quad by a long
112→constexpr int32_t fixdivquadlong(int64_t n, uint32_t d)
113→{
114→	if (d == 0) return 1;
115→	return (int32_t)(n / d);
116→}
117→
118→//negate a quad
119→void fixquadnegate(quad* q);
120→
121→//computes the square root of a long, returning a short
122→uint16_t long_sqrt(int32_t a);
123→
124→//computes the square root of a quad, returning a long
125→uint32_t quad_sqrt(int64_t q);
126→
127→//computes the square root of a fix, returning a fix
128→fix fix_sqrt(fix a);
129→
130→//compute sine and cosine of an angle, filling in the variables
131→//either of the pointers can be NULL
132→void fix_sincos(fix a, fix* s, fix* c);		//with interpolation
133→void fix_fastsincos(fix a, fix* s, fix* c);	//no interpolation
134→
135→//compute inverse sine & cosine
136→fixang fix_asin(fix v);
137→fixang fix_acos(fix v);
138→
139→//given cos & sin of an angle, return that angle.
140→//parms need not be normalized, that is, the ratio of the parms cos/sin must
141→//equal the ratio of the actual cos & sin for the result angle, but the parms 
142→//need not be the actual cos & sin.  
143→//NOTE: this is different from the standard C atan2, since it is left-handed.
144→fixang fix_atan2(fix cos, fix sin);
145→
146→//for passed value a, returns 1/sqrt(a) 
147→fix fix_isqrt(fix a);
