	uint32_t frame = frames_replayed;
	fwrite(&frame, sizeof(frame), 1, state_log);

	/* Write key game state: objects up to Highest_object_index */
	int n_obj = Highest_object_index + 1;
	if (n_obj > MAX_OBJECTS) n_obj = MAX_OBJECTS;

	int32_t n = n_obj;
