	}

	/* Write players */
	fwrite(Players, sizeof(player), MAX_PLAYERS, state_log);

	/* Write globals */
	int32_t globals[5];
	globals[0] = Player_is_dead;
	globals[1] = Player_exploded;
	globals[2] = Overall_agitation;
